sql:
SELECT simulation_id, status
FROM simulations
WHERE vdwaals > -30 AND status = 'success';

SELECT version
FROM simulation_versions
WHERE simulation_id = 0 AND is_current = 1;

SELECT energy_type, value 
FROM energy_values 
WHERE value < 0 AND simulation_id = 0;

SELECT simulation_id
FROM simulations
WHERE total > (SELECT AVG(total) FROM simulations);

SELECT created_date
FROM simulation_versions
WHERE simulation_id = 0 AND is_current = 1;

SELECT COUNT(simulation_id)
FROM simulations
WHERE status = 'completed' AND end_date >= DATE('now', '-30 days');

SELECT simulations.simulation_id, stages.stage_name
FROM simulations
JOIN stages ON simulations.stage_id = stages.stage_id;

SELECT type_name, description
FROM simulation_types
WHERE type_id = 1;

external_knowledge:
- "Riding the crest of the recent technological wave" refers to conducting simulations that are at the forefront of technology;
- "Simulations that have sparked more than a hundred flames of innovation" represents simulations with a value greater than 100 in energy_values;
- "Within the last month" means the start date of the simulation is within the last 30 days.
